// AutoResearchClaw artifacts → Mories memory items
const body = $input.first().json.body || $input.first().json;
const artifactsDir = body.artifacts_dir || '';
const topic = body.topic || 'Unknown Research';
const runId = body.run_id || `rc-${Date.now()}`;
const graphId = body.graph_id || $env.MORIES_GRAPH_ID || 'research';

const items = [];

// 1. Paper Draft → high salience knowledge
if (body.paper_draft) {
  items.push({
    json: {
      content: `[Research Paper] ${topic}\n\n${body.paper_draft.substring(0, 5000)}`,
      source: `researchclaw:${runId}:paper`,
      graph_id: graphId,
      scope: 'tribal',
      salience: 0.9,
      metadata: {
        type: 'paper_draft',
        run_id: runId,
        topic: topic,
        stage: 'PAPER_DRAFT'
      }
    }
  });
}

// 2. Literature references → individual memories
if (body.references && Array.isArray(body.references)) {
  for (const ref of body.references.slice(0, 50)) {
    items.push({
      json: {
        content: `[Citation] ${ref.title || ref.key || 'Unknown'} by ${ref.authors || 'Unknown'} (${ref.year || 'N/A'})\nAbstract: ${(ref.abstract || ref.summary || '').substring(0, 1000)}`,
        source: `researchclaw:${runId}:citation`,
        graph_id: graphId,
        scope: 'tribal',
        salience: 0.6,
        metadata: {
          type: 'citation',
          run_id: runId,
          doi: ref.doi || '',
          url: ref.url || '',
          year: ref.year || ''
        }
      }
    });
  }
}

// 3. Experiment results → technical knowledge
if (body.experiment_results) {
  const results = typeof body.experiment_results === 'string'
    ? body.experiment_results
    : JSON.stringify(body.experiment_results, null, 2);
  items.push({
    json: {
      content: `[Experiment Results] ${topic}\n\n${results.substring(0, 3000)}`,
      source: `researchclaw:${runId}:experiment`,
      graph_id: graphId,
      scope: 'tribal',
      salience: 0.8,
      metadata: {
        type: 'experiment_result',
        run_id: runId,
        topic: topic,
        stage: 'EXPERIMENT_RUN'
      }
    }
  });
}

// 4. Peer review feedback → meta-knowledge
if (body.reviews) {
  items.push({
    json: {
      content: `[Peer Review] ${topic}\n\n${(typeof body.reviews === 'string' ? body.reviews : JSON.stringify(body.reviews)).substring(0, 2000)}`,
      source: `researchclaw:${runId}:review`,
      graph_id: graphId,
      scope: 'tribal',
      salience: 0.7,
      metadata: {
        type: 'peer_review',
        run_id: runId,
        topic: topic,
        stage: 'PEER_REVIEW'
      }
    }
  });
}

// 5. Synthesis/Hypotheses → theoretical knowledge
if (body.synthesis) {
  items.push({
    json: {
      content: `[Research Synthesis] ${topic}\n\n${(typeof body.synthesis === 'string' ? body.synthesis : JSON.stringify(body.synthesis)).substring(0, 3000)}`,
      source: `researchclaw:${runId}:synthesis`,
      graph_id: graphId,
      scope: 'tribal',
      salience: 0.85,
      metadata: {
        type: 'synthesis',
        run_id: runId,
        topic: topic,
        stage: 'SYNTHESIS'
      }
    }
  });
}

// 6. Lessons learned (MetaClaw skills) → high-value operational memory
if (body.lessons && Array.isArray(body.lessons)) {
  for (const lesson of body.lessons) {
    items.push({
      json: {
        content: `[Research Lesson] ${lesson.title || 'Lesson'}\n${lesson.description || lesson.content || JSON.stringify(lesson)}`,
        source: `researchclaw:${runId}:lesson`,
        graph_id: graphId,
        scope: 'global',
        salience: 0.95,
        metadata: {
          type: 'lesson_learned',
          run_id: runId,
          severity: lesson.severity || 'info',
          stage: lesson.stage || 'unknown'
        }
      }
    });
  }
}

// Fallback: if nothing was extracted, store raw payload summary
if (items.length === 0) {
  items.push({
    json: {
      content: `[Research Run Complete] ${topic}\n\nRun ID: ${runId}\nPayload keys: ${Object.keys(body).join(', ')}`,
      source: `researchclaw:${runId}:summary`,
      graph_id: graphId,
      scope: 'tribal',
      salience: 0.5,
      metadata: { type: 'run_summary', run_id: runId, topic: topic }
    }
  });
}

return items;
